- The "mentioned area" refers to 'YourSpecificRegion'.;
- "On a specific day" means the date provided as 'YourSpecificDate'.;
- "Currently on the rise" refers to 'new_cases' - the number of new cases reported for each symptom type.;

sql:
SELECT hr.resource_type, AVG(hr.quantity) AS AverageQuantity, SUM(hr.capacity) AS TotalCapacity
FROM healthcare_resources hr
GROUP BY hr.resource_type;

SELECT resource_id, region_id
FROM healthcare_resources
WHERE status = 'available';

SELECT symptom_type
FROM symptoms_data
WHERE region_id = 0;
